/* ─────────────────── HELPERS ─────────────────── */
const splitList = (v) =>
  String(v || "")
    .split(";")
    .map((x) => x.trim())
    .filter(Boolean);

const uniqSorted = (arr) =>
  Array.from(new Set(arr.filter(Boolean))).sort((a, b) =>
    a.localeCompare(b, "id"),
  );

/* ─────────────────── SUB COMPONENTS ─────────────────── */
function FieldLabel({ children }) {
  return (
    <div
      style={{
        fontSize: 11,
        fontWeight: 700,
        letterSpacing: "0.08em",
        textTransform: "uppercase",
        color: "#6b7280",
        marginBottom: 8,
        display: "flex",
        alignItems: "center",
      }}
    >
      {children}
    </div>
  );
}

function NativeSelect({ value, onChange, options, placeholder, disabled }) {
  return (
    <div style={{ position: "relative" }}>
      <select
        value={value}
        disabled={disabled}
        onChange={(e) => onChange(e.target.value)}
        style={{
          width: "100%",
          padding: "12px 40px 12px 14px",
          border: "2px solid #e5e7eb",
          borderRadius: 12,
          fontSize: 14,
          fontWeight: 500,
          color: value ? "#111827" : "#9ca3af",
          background: disabled ? "#f9fafb" : "#fff",
          outline: "none",
          appearance: "none",
          fontFamily: "inherit",
          cursor: disabled ? "not-allowed" : "pointer",
        }}
      >
        <option value="">{placeholder}</option>
        {options.map((o) => (
          <option key={o} value={o}>
            {o}
          </option>
        ))}
      </select>
      <ChevronDown
        size={16}
        style={{
          position: "absolute",
          right: 14,
          top: "50%",
          transform: "translateY(-50%)",
          color: "#6b7280",
          pointerEvents: "none",
        }}
      />
    </div>
  );
}

function OutputBlock({ icon, label, children, accent = "#0ea5e9" }) {
  return (
    <div
      style={{
        background: "#fff",
        border: "1.5px solid #e2e8f0",
        borderRadius: 14,
        padding: "18px 20px",
        marginBottom: 14,
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 10,
          marginBottom: 12,
        }}
      >
        <div
          style={{
            width: 32,
            height: 32,
            borderRadius: 8,
            background: accent + "15",
            color: accent,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          {icon}
        </div>
        <div
          style={{
            fontSize: 12,
            fontWeight: 700,
            letterSpacing: "0.08em",
            textTransform: "uppercase",
            color: "#475569",
          }}
        >
          {label}
        </div>
      </div>
      <div
        style={{
          fontSize: 13,
          color: "#1f2937",
          lineHeight: 1.65,
          whiteSpace: "pre-wrap",
        }}
      >
        {children}
      </div>
    </div>
  );
}

/* ─────────────────── MAIN COMPONENT ─────────────────── */
export default function TaxSuperDeduction() {
  const [jenisIndustri, setJenisIndustri] = useState("");
  const [produk, setProduk] = useState("");
  const [lokasi, setLokasi] = useState("");
  const [kawasan, setKawasan] = useState("");
  const [jenisInsentif, setJenisInsentif] = useState("");
  const [result, setResult] = useState(null);
  const [isCalculating, setIsCalculating] = useState(false);

  /* Cascading options based on Pemetaan Website flow:
     Jenis_Industri → Produk → Lokasi → Kawasan_Industri → Jenis_Insentif */
  const filteredByIndustri = useMemo(
    () =>
      jenisIndustri
        ? DATA.filter((d) => d.jenisIndustri === jenisIndustri)
        : DATA,
    [jenisIndustri],
  );
  const filteredByProduk = useMemo(
    () =>
      produk
        ? filteredByIndustri.filter((d) => d.produk === produk)
        : filteredByIndustri,
    [filteredByIndustri, produk],
  );
  const filteredByLokasi = useMemo(
    () =>
      lokasi
        ? filteredByProduk.filter((d) => splitList(d.lokasi).includes(lokasi))
        : filteredByProduk,
    [filteredByProduk, lokasi],
  );
  const filteredByKawasan = useMemo(
    () =>
      kawasan
        ? filteredByLokasi.filter((d) => splitList(d.kawasan).includes(kawasan))
        : filteredByLokasi,
    [filteredByLokasi, kawasan],
  );

  const jenisIndustriOpts = useMemo(
    () => uniqSorted(DATA.map((d) => d.jenisIndustri)),
    [],
  );
  const produkOpts = useMemo(
    () => uniqSorted(filteredByIndustri.map((d) => d.produk)),
    [filteredByIndustri],
  );
  const lokasiOpts = useMemo(
    () => uniqSorted(filteredByProduk.flatMap((d) => splitList(d.lokasi))),
    [filteredByProduk],
  );
  const kawasanOpts = useMemo(
    () => uniqSorted(filteredByLokasi.flatMap((d) => splitList(d.kawasan))),
    [filteredByLokasi],
  );
  const jenisInsentifOpts = useMemo(
    () => uniqSorted(DATA.map((d) => d.jenisInsentif)),
    [],
  );

  const canSimulate =
    jenisIndustri &&
    produk &&
    lokasi &&
    kawasan &&
    jenisInsentif &&
    !isCalculating;

  const handleSimulate = () => {
    if (!canSimulate) return;
    setIsCalculating(true);
    setResult(null);
    setTimeout(() => {
      const matches = filteredByKawasan.filter(
        (d) => d.jenisInsentif === jenisInsentif,
      );
      if (matches.length === 0) {
        setResult({ status: "error" });
      } else {
        setResult({ status: "success", matches });
      }
      setIsCalculating(false);
    }, 400);
  };

  const handleReset = () => {
    setJenisIndustri("");
    setProduk("");
    setLokasi("");
    setKawasan("");
    setJenisInsentif("");
    setResult(null);
  };

  const handleDownload = () => {
    if (!result || result.status !== "success") return;
    const esc = (v) => {
      const s = (v ?? "").toString().replace(/\r?\n/g, " ").trim();
      return `"${s.replace(/"/g, '""')}"`;
    };
    const headers = [
      "No",
      "Jenis Industri",
      "Produk",
      "Lokasi",
      "Kawasan Industri",
      "Jenis Insentif",
      "Ketentuan",
      "Detail Insentif",
      "Syarat",
      "Cakupan",
      "Insentif Tambahan",
      "Dasar Hukum",
    ];
    const rows = result.matches.map((m, i) => [
      i + 1,
      jenisIndustri,
      produk,
      lokasi,
      kawasan,
      jenisInsentif,
      m.ketentuan,
      m.detailInsentif,
      m.syarat,
      m.cakupan,
      m.insentifTambahan,
      m.dasarHukum,
    ]);
    const csv = [headers, ...rows]
      .map((r) => r.map(esc).join(","))
      .join("\r\n");
    // BOM agar Excel (terutama versi ID) membuka UTF-8 dengan benar
    const blob = new Blob(["\uFEFF" + csv], {
      type: "text/csv;charset=utf-8;",
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `simulasi-super-tax-deduction-${Date.now()}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div
      style={{
        maxWidth: 1280,
        margin: "0 auto",
        padding: "32px 24px",
        fontFamily: "inherit",
      }}
    >
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1.15fr",
          gap: 32,
          alignItems: "start",
        }}
      >
        {/* LEFT: FORM */}
        <div
          style={{
            background: "#fff",
            border: "1.5px solid #e2e8f0",
            borderRadius: 20,
            padding: 28,
            boxShadow: "0 8px 24px rgba(15,23,42,.05)",
          }}
        >
          <div style={{ marginBottom: 24 }}>
            <h3
              style={{
                fontSize: 17,
                fontWeight: 700,
                color: "#111827",
                margin: "0 0 4px",
              }}
            >
              Parameter Simulasi
            </h3>
            <p style={{ fontSize: 13, color: "#6b7280", margin: 0 }}>
              Filter bertingkat berdasarkan database substantif STD.
            </p>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
            <div>
              <FieldLabel>
                <Briefcase size={10} style={{ marginRight: 4 }} /> Jenis
                Industri
              </FieldLabel>
              <NativeSelect
                value={jenisIndustri}
                options={jenisIndustriOpts}
                placeholder="Pilih jenis industri"
                onChange={(v) => {
                  setJenisIndustri(v);
                  setProduk("");
                  setLokasi("");
                  setKawasan("");
                  setJenisInsentif("");
                  setResult(null);
                }}
              />
            </div>
            <div>
              <FieldLabel>
                <Package size={10} style={{ marginRight: 4 }} /> Produk
              </FieldLabel>
              <NativeSelect
                value={produk}
                options={produkOpts}
                placeholder="Pilih produk / aktivitas"
                disabled={!jenisIndustri}
                onChange={(v) => {
                  setProduk(v);
                  setLokasi("");
                  setKawasan("");
                  setJenisInsentif("");
                  setResult(null);
                }}
              />
            </div>
            <div>
              <FieldLabel>
                <MapPin size={10} style={{ marginRight: 4 }} /> Lokasi
              </FieldLabel>
              <NativeSelect
                value={lokasi}
                options={lokasiOpts}
                placeholder="Pilih provinsi"
                disabled={!produk}
                onChange={(v) => {
                  setLokasi(v);
                  setKawasan("");
                  setJenisInsentif("");
                  setResult(null);
                }}
              />
            </div>
            <div>
              <FieldLabel>
                <Building size={10} style={{ marginRight: 4 }} /> Kawasan
                Industri
              </FieldLabel>
              <NativeSelect
                value={kawasan}
                options={kawasanOpts}
                placeholder="Pilih kawasan industri"
                disabled={!lokasi}
                onChange={(v) => {
                  setKawasan(v);
                  setJenisInsentif("");
                  setResult(null);
                }}
              />
            </div>
            <div>
              <FieldLabel>
                <Layers size={10} style={{ marginRight: 4 }} /> Jenis Insentif
              </FieldLabel>
              <NativeSelect
                value={jenisInsentif}
                options={jenisInsentifOpts}
                placeholder="Pilih jenis insentif"
                disabled={!kawasan}
                onChange={(v) => {
                  setJenisInsentif(v);
                  setResult(null);
                }}
              />
            </div>
          </div>

          <div style={{ display: "flex", gap: 12, marginTop: 28 }}>
            <button
              onClick={handleSimulate}
              disabled={!canSimulate}
              style={{
                flex: 1,
                padding: "14px 20px",
                borderRadius: 12,
                border: "none",
                cursor: canSimulate ? "pointer" : "not-allowed",
                background: canSimulate
                  ? "linear-gradient(135deg,#10b981,#059669)"
                  : "#e5e7eb",
                color: canSimulate ? "#fff" : "#9ca3af",
                fontSize: 14,
                fontWeight: 700,
                boxShadow: canSimulate
                  ? "0 4px 14px rgba(16,185,129,0.3)"
                  : "none",
                transition: "all 0.2s",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 8,
              }}
            >
              {isCalculating ? (
                <motion.div
                  animate={{ rotate: 360 }}
                  transition={{
                    duration: 0.8,
                    repeat: Infinity,
                    ease: "linear",
                  }}
                  style={{
                    width: 18,
                    height: 18,
                    border: "2px solid rgba(255,255,255,0.3)",
                    borderTopColor: "#fff",
                    borderRadius: "50%",
                  }}
                />
              ) : (
                <>
                  <Search size={16} /> Simulasikan
                </>
              )}
            </button>
            <button
              onClick={handleReset}
              title="Reset"
              style={{
                padding: "14px 16px",
                borderRadius: 12,
                border: "2px solid #e5e7eb",
                background: "#fff",
                cursor: "pointer",
                color: "#6b7280",
              }}
            >
              <RefreshCcw size={16} />
            </button>
          </div>

          <div
            style={{
              marginTop: 18,
              background: "#f0fdf4",
              border: "1px solid #bbf7d0",
              borderRadius: 10,
              padding: "10px 14px",
              fontSize: 12,
              color: "#065f46",
              lineHeight: 1.55,
            }}
          >
            💡 Filter bersifat cascading: setiap pilihan menyempitkan opsi
            berikutnya berdasarkan {DATA.length} entri database substantif.
          </div>
        </div>

        {/* RIGHT: RESULT */}
        <div
          style={{
            background: "linear-gradient(145deg,#f8fafc,#f1f5f9)",
            borderRadius: 20,
            border: "1.5px solid #e2e8f0",
            minHeight: 540,
            padding: 28,
            display: "flex",
            flexDirection: "column",
          }}
        >
          <AnimatePresence mode="wait">
            {!result && !isCalculating && (
              <motion.div
                key="empty"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                style={{
                  flex: 1,
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  justifyContent: "center",
                  textAlign: "center",
                }}
              >
                <div
                  style={{
                    width: 64,
                    height: 64,
                    borderRadius: "50%",
                    background: "#d1fae5",
                    border: "2px solid #6ee7b7",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    marginBottom: 16,
                  }}
                >
                  <Search size={28} color="#10b981" />
                </div>
                <div
                  style={{
                    fontSize: 17,
                    fontWeight: 700,
                    color: "#1f2937",
                    marginBottom: 8,
                  }}
                >
                  Pilih Parameter untuk Memulai
                </div>
                <p
                  style={{
                    fontSize: 13,
                    color: "#94a3b8",
                    maxWidth: 280,
                    lineHeight: 1.65,
                    margin: 0,
                  }}
                >
                  Lengkapi parameter di kiri untuk melihat detail insentif,
                  syarat, cakupan, dan dasar hukum.
                </p>
              </motion.div>
            )}

            {isCalculating && (
              <motion.div
                key="loading"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                style={{
                  flex: 1,
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <motion.div
                  animate={{ rotate: 360 }}
                  transition={{
                    duration: 1.2,
                    repeat: Infinity,
                    ease: "linear",
                  }}
                  style={{
                    width: 52,
                    height: 52,
                    border: "3px solid #d1fae5",
                    borderTopColor: "#10b981",
                    borderRadius: "50%",
                    marginBottom: 16,
                  }}
                />
                <div
                  style={{
                    fontSize: 13,
                    fontWeight: 600,
                    color: "#059669",
                    letterSpacing: "0.08em",
                    textTransform: "uppercase",
                  }}
                >
                  Memproses Data
                </div>
              </motion.div>
            )}

            {result?.status === "error" && (
              <motion.div
                key="error"
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
              >
                <div
                  style={{
                    background: "#fef2f2",
                    border: "1.5px solid #fecaca",
                    borderRadius: 14,
                    padding: "16px 20px",
                    display: "flex",
                    gap: 14,
                  }}
                >
                  <XCircle
                    size={22}
                    color="#ef4444"
                    style={{ flexShrink: 0 }}
                  />
                  <div>
                    <div
                      style={{
                        fontSize: 14,
                        fontWeight: 700,
                        color: "#dc2626",
                        marginBottom: 4,
                      }}
                    >
                      Data Tidak Ditemukan
                    </div>
                    <div
                      style={{
                        fontSize: 13,
                        color: "#b91c1c",
                        lineHeight: 1.55,
                      }}
                    >
                      Kombinasi parameter tidak tersedia pada database STD.
                    </div>
                  </div>
                </div>
              </motion.div>
            )}

            {result?.status === "success" && (
              <motion.div
                key="success"
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
              >
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    marginBottom: 18,
                  }}
                >
                  <div
                    style={{ display: "flex", alignItems: "center", gap: 10 }}
                  >
                    <div
                      style={{
                        width: 34,
                        height: 34,
                        borderRadius: "50%",
                        background: "#d1fae5",
                        border: "1.5px solid #6ee7b7",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                      }}
                    >
                      <CheckCircle2 size={18} color="#059669" />
                    </div>
                    <div>
                      <div
                        style={{
                          fontSize: 14,
                          fontWeight: 700,
                          color: "#059669",
                        }}
                      >
                        {result.matches.length} Hasil Ditemukan
                      </div>
                      <div style={{ fontSize: 11, color: "#94a3b8" }}>
                        Indikasi kelayakan berdasarkan database substantif
                      </div>
                    </div>
                  </div>
                  <button
                    onClick={handleDownload}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 6,
                      padding: "8px 14px",
                      background: "#059669",
                      color: "#fff",
                      border: "none",
                      borderRadius: 10,
                      fontSize: 12,
                      fontWeight: 600,
                      cursor: "pointer",
                    }}
                  >
                    <Download size={14} /> Unduh Laporan
                  </button>
                </div>

                <div
                  style={{ maxHeight: 620, overflowY: "auto", paddingRight: 4 }}
                >
                  {result.matches.map((m, idx) => (
                    <div key={idx} style={{ marginBottom: 22 }}>
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: 8,
                          marginBottom: 10,
                        }}
                      >
                        <span
                          style={{
                            fontSize: 11,
                            fontWeight: 700,
                            color: "#fff",
                            background: "#059669",
                            padding: "3px 9px",
                            borderRadius: 6,
                          }}
                        >
                          #{idx + 1}
                        </span>
                        <span
                          style={{
                            fontSize: 12,
                            fontWeight: 600,
                            color: "#475569",
                          }}
                        >
                          {m.ketentuan}
                        </span>
                      </div>
                      <OutputBlock
                        icon={<Sparkles size={16} />}
                        label="Detail Insentif"
                        accent="#10b981"
                      >
                        {m.detailInsentif}
                      </OutputBlock>
                      <OutputBlock
                        icon={<FileText size={16} />}
                        label="Syarat"
                        accent="#0d9488"
                      >
                        {m.syarat}
                      </OutputBlock>
                      <OutputBlock
                        icon={<Layers size={16} />}
                        label="Cakupan"
                        accent="#0f766e"
                      >
                        {m.cakupan}
                      </OutputBlock>
                      {m.insentifTambahan && (
                        <OutputBlock
                          icon={<Package size={16} />}
                          label="Insentif Tambahan"
                          accent="#059669"
                        >
                          {m.insentifTambahan}
                        </OutputBlock>
                      )}
                      <OutputBlock
                        icon={<Scale size={16} />}
                        label="Dasar Hukum"
                        accent="#b45309"
                      >
                        {m.dasarHukum}
                        {m.urlHukum && (
                          <div style={{ marginTop: 6 }}>
                            <a
                              href={m.urlHukum}
                              target="_blank"
                              rel="noreferrer"
                              style={{ fontSize: 12, color: "#059669" }}
                            >
                              Sumber regulasi ↗
                            </a>
                          </div>
                        )}
                      </OutputBlock>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </div>
  );
}
